// Parse Vapi end-of-call report
const items = $input.all();
const body = items[0].json.body || items[0].json;
const message = body.message || body;
const call = message.call || {};
const analysis = message.analysis || {};
const structuredData = analysis.structuredData || {};
const summary = analysis.summary || '';

// Calculate call duration
const startedAt = call.startedAt ? new Date(call.startedAt) : null;
const endedAt = call.endedAt ? new Date(call.endedAt) : null;
let durationStr = '';
if (startedAt && endedAt) {
  const durationMs = endedAt - startedAt;
  const durationMin = Math.floor(durationMs / 60000);
  const durationSec = Math.floor((durationMs % 60000) / 1000);
  durationStr = durationMin + ':' + String(durationSec).padStart(2, '0');
}

// Format date and time (Berlin timezone)
const now = new Date();
const dateStr = now.toLocaleDateString('de-DE', { timeZone: 'Europe/Berlin' });
const timeStr = now.toLocaleTimeString('de-DE', { timeZone: 'Europe/Berlin', hour: '2-digit', minute: '2-digit' });

// Determine if resolved
const followUp = structuredData.followUpNeeded;
const resolved = followUp === true ? 'Nie' : followUp === false ? 'Tak' : '';

// Get phone number
const phoneNumber = structuredData.callerContact || (call.customer ? call.customer.number : '') || '';

// Build notes
const notes = [];
if (structuredData.callerName) notes.push('Imię: ' + structuredData.callerName);
if (structuredData.languageUsed) notes.push('Język: ' + structuredData.languageUsed);
if (structuredData.topicRequest) notes.push('Temat: ' + structuredData.topicRequest);

return [{
  json: {
    'Data': dateStr,
    'Godzina': timeStr,
    'Podsumowanie rozmowy': summary,
    'Rozwiązane?': resolved,
    'Numer telefonu': phoneNumber,
    'Czas rozmowy': durationStr,
    'Notatki': notes.join(' | ')
  }
}];
